parameters.jsCode:
// ============================================================
// CLEAR CACHE & CONFIRM — Surgical Cache Patch  v3.1
//
// CHANGE FROM v2: Instead of wiping all 9 cache keys (forcing a
// cold Firestore read for every user on next request), this node
// now patches the existing cache in place:
//   • Appends the new lead to KEY_LEADS
//   • Increments the relevant aggregation counters
//   • Updates total, totalDealValue, firestoreCount, cachedAt
//   • topDealsByRep is re-sorted in place if dealValue > 0
//
// If no cache exists yet for this tenant, a full wipe (the old
// behaviour) is still performed so the next request triggers a
// clean Firestore fetch — no partial state risk.
//
// NOTE: addlead_session cleanup is handled upstream by
// Check Save Result (error path) and Evaluate Duplicate —
// no need to repeat it here.
// ============================================================

const sd  = $getWorkflowStaticData('global');
const d   = $input.first().json;

const msg            = $('Telegram Trigger').first().json?.message;
const telegramUserId = String(msg?.from?.id || '');
const chatId         = String(msg?.chat?.id || msg?.from?.id || '');

delete sd[`addlead_session_${telegramUserId}`];

const tenantId = d.tenantId || '';

// ── Pull saved fields from Check Save Result chain ────────────
const saveData   = d.data || $('Check Save Result').first().json?.data || {};
const leadName   = saveData.fullName   || d.fullName   || 'Lead';
const company    = saveData.company    || '';
const phone      = saveData.phone      || '';
const email      = saveData.email      || '';
const service    = saveData.service    || '';
const source     = saveData.source     || '';
const assignedTo = saveData.assignedTo || 'Unassigned';
const dealValue  = Number(
  d.data?.dealValue
  ?? $('Check Save Result').first().json?.data?.dealValue
  ?? d.dealValue
  ?? $('Input Fields').first().json?.dealValue
  ?? 0
) || 0;
const industry   = saveData.industry   || '';
const followup   = saveData.followup   || '';
const notes      = saveData.notes      || '';
const firestoreDocId = $('Check Save Result').first().json?.firestoreDocId || '';

// ── Scoring (mirrors Slim Payload logic) ─────────────────────
const has = v => v && v !== 'unknown' && v !== 'unassigned';
let score = 0;
if (has(email))   score += 10;
if (has(phone))   score += 15;
if (has(company)) score += 10;
if (has(service)) score += 10;
score += 5; // new stage
if (dealValue > 0) score += Math.min(20, Math.floor(dealValue / 5000));
score = Math.min(100, score);

const tier      = score >= 60 ? 'HOT' : score >= 35 ? 'WARM' : 'COLD';
const tierEmoji = { HOT: '🔴', WARM: '🟡', COLD: '🔵' }[tier];

// ── Deal value formatting ─────────────────────────────────────
const dealFmt = dealValue > 0
  ? Number(dealValue).toLocaleString('en-IN')
  : '';

// ── Table: 2 columns only — Field | Value ─────────────────────
function pad(s, n) { return String(s).padEnd(n); }
const C1  = 18;
const sep = '-'.repeat(C1 + 22);
const hdr = pad('Field', C1) + 'Value';

const rows = [
  ['Name',        leadName],
  company    ? ['Company',     company]    : null,
  email      ? ['Email',       email]      : null,
  phone      ? ['Phone',       phone]      : null,
  ['Stage',       'New'],
  dealFmt    ? ['Deal Value',  dealFmt]    : null,
  service    ? ['Service',     service]    : null,
  industry   ? ['Industry',    industry]   : null,
  assignedTo && assignedTo !== 'Unassigned'
               ? ['Assigned To', assignedTo] : null,
  source     ? ['Source',      source]     : null,
  followup   ? ['Follow Up',   followup]   : null,
  notes      ? ['Notes',       notes]      : null,
].filter(Boolean);

const tableRows = rows.map(([f, v]) => pad(f, C1) + v).join('\n');
const table = hdr + '\n' + sep + '\n' + tableRows + '\n' + sep;

const message =
  `✅ <b>Lead saved!</b>\n` +
  `${tierEmoji} <b>New Lead View</b>\n` +
  `<pre>${table}</pre>`;

// ── SURGICAL CACHE PATCH ──────────────────────────────────────
// Only patch if a valid cache exists for this tenant.
// If cache is absent, fall through — next request triggers a
// clean Firestore fetch naturally via Read Session Cache TTL logic.

if (tenantId) {
  const KEY_PREFIX      = `tenant_${tenantId}`;
  const KEY_LEADS       = `${KEY_PREFIX}_leadsCache`;
  const KEY_AGGREGATION = `${KEY_PREFIX}_aggregationSnapshot`;
  const KEY_TOTAL       = `${KEY_PREFIX}_leadTotal`;
  const KEY_TOTAL_ALL   = `${KEY_PREFIX}_totalAll`;
  const KEY_DEAL_VALUE  = `${KEY_PREFIX}_totalDealValue`;
  const KEY_FS_COUNT    = `${KEY_PREFIX}_firestoreCount`;
  const KEY_TOP_DEALS   = `${KEY_PREFIX}_topDealsByRep`;

  const cacheExists = !!sd[KEY_LEADS] && !!sd[KEY_AGGREGATION];

  if (cacheExists) {
    let patchFailed = false;

    // ── 1. Append to leadsCache ──────────────────────────────
    try {
      const newLead = {
        leadId:            firestoreDocId,
        tenantId,
        name:              leadName,
        company:           company || '',
        email:             email   || '',
        phone:             phone   || '',
        status:            'new',
        service:           (service  || 'unknown').toLowerCase().trim(),
        industry:          (industry || 'unknown').toLowerCase().trim(),
        assignedTo:        (assignedTo || 'unassigned').toLowerCase().trim(),
        assignedToDisplay: (assignedTo || 'Unassigned').trim(),
        source:            (source   || 'unknown').toLowerCase().trim(),
        dealValue:         Number(dealValue) || 0,
        followup:          followup || null,
        createdAt:         new Date().toISOString()
      };

      const leads = JSON.parse(sd[KEY_LEADS] || '[]');
      leads.push(newLead);
      sd[KEY_LEADS] = JSON.stringify(leads);

      // ── 2. Patch aggregation snapshot ──────────────────────
      try {
        const agg = JSON.parse(sd[KEY_AGGREGATION] || '{}');

        if (agg.status)   agg.status['new'] = (agg.status['new'] || 0) + 1;
        if (agg.service && newLead.service)
          agg.service[newLead.service]       = (agg.service[newLead.service] || 0) + 1;
        if (agg.industry && newLead.industry)
          agg.industry[newLead.industry]     = (agg.industry[newLead.industry] || 0) + 1;
        if (agg.assignedTo)
          agg.assignedTo[newLead.assignedToDisplay] = (agg.assignedTo[newLead.assignedToDisplay] || 0) + 1;
        if (agg.source && newLead.source)
          agg.source[newLead.source]         = (agg.source[newLead.source] || 0) + 1;
        if (agg.company && newLead.company)
          agg.company[newLead.company]       = (agg.company[newLead.company] || 0) + 1;

        sd[KEY_AGGREGATION] = JSON.stringify(agg);
      } catch { /* aggregation patch failed — totals still correct */ }

      // ── 3. Update totals ────────────────────────────────────
      const prevTotal = Number(sd[KEY_TOTAL] || 0);
      sd[KEY_TOTAL]     = String(prevTotal + 1);
      sd[KEY_TOTAL_ALL] = String(prevTotal + 1);
      sd[KEY_FS_COUNT]  = String(prevTotal + 1);

      const prevDeal = Number(sd[KEY_DEAL_VALUE] || 0);
      sd[KEY_DEAL_VALUE] = String(prevDeal + (Number(dealValue) || 0));

      // ── 4. Patch topDealsByRep ──────────────────────────────
      if (Number(dealValue) > 0) {
        try {
          const top = JSON.parse(sd[KEY_TOP_DEALS] || '{}');
          const rep = newLead.assignedToDisplay;
          if (!top[rep]) top[rep] = [];
          top[rep].push({
            name:      newLead.name,
            company:   newLead.company,
            dealValue: Number(dealValue) || 0,
            status:    'new'
          });
          top[rep].sort((a, b) => b.dealValue - a.dealValue);
          sd[KEY_TOP_DEALS] = JSON.stringify(top);
        } catch { /* topDealsByRep patch failed — non-critical */ }
      }

    } catch {
      // leads parse/stringify failed — wipe cache so next request
      // does a clean Firestore fetch rather than serving stale data
      patchFailed = true;
    }

    if (patchFailed) {
      ['_leadsCache','_aggregationSnapshot','_leadTotal','_totalAll',
       '_totalDealValue','_filtersApplied','_firestoreCount','_cachedAt','_topDealsByRep']
        .forEach(k => delete sd[`${KEY_PREFIX}${k}`]);
    }

  }
  // No cache present — do nothing. Read Session Cache will fetch
  // fresh from Firestore on the next request naturally.
}

return [{ json: { chatId, message } }];

// Map Firestore auto-generated doc ID to leadId field for the update
const input = $input.first().json;

// firestoreDocId forwarded from Check Save Result
const firestoreDocId = input.firestoreDocId || '';

return [{ json: {
  ...input,
  leadId:          firestoreDocId,
  firestoreDocId:  firestoreDocId,
  documentId:      firestoreDocId
}}];

// ============================================================
// BUILD ERROR MESSAGE
// chatId always from Telegram Trigger — never trust upstream empty field
// ============================================================
const d   = $input.first().json;
const sd  = $getWorkflowStaticData('global');

const msg            = $('Telegram Trigger').first().json?.message;
const telegramUserId = String(msg?.from?.id || '');
const chatId         = String(msg?.chat?.id || msg?.from?.id || '');

delete sd[`addlead_session_${telegramUserId}`];

const code = d.statusCode || 0;
let message = '';

if (code === 403) {
  message = `🚫 You don't have permission to add leads.\n\nPlease contact your administrator to get access.`;
} else if (code >= 500) {
  message = `⚠️ Something went wrong saving your lead. Please try again in a moment.`;
} else {
  message = `⚠️ Couldn't save the lead. Please try again or contact your administrator.`;
}

return [{ json: {
  chatId,
  message: `${message}\n\nType /addlead to try again.`
}}];

// ============================================================
// CHECK SAVE RESULT
// chatId + telegramUserId always from Telegram Trigger
// tenantId from static data user_tenant_map
// data reconstructed from post-lead echoed fields
// ============================================================
const sd  = $getWorkflowStaticData('global');
const input = $input.first().json;

// Always-reliable — never depend on post-lead echo for these
const msg            = $('Telegram Trigger').first().json?.message;
const telegramUserId = String(msg?.from?.id || '');
const chatId         = String(msg?.chat?.id || msg?.from?.id || '');

let tenantId = '';
try {
  const userMap = sd['user_tenant_map'] ? JSON.parse(sd['user_tenant_map']) : {};
  // user_tenant_map stores {tenantId, role} objects — extract .tenantId only
  const rawEntry = userMap[telegramUserId] || null;
  tenantId = (rawEntry && typeof rawEntry === 'object') ? (rawEntry.tenantId || '') : (rawEntry || '');
} catch {}

// These ARE echoed by post-lead (they are listed in columns)
const reference_lead_id = input.reference_lead_id || '';

// Firestore auto-generated doc ID returned as metadata by the Create node
const firestoreDocId = input._id || '';

const data = {
  fullName:   input.fullName   || '',
  email:      input.email      || '',
  phone:      input.phone      || '',
  company:    input.company    || '',
  service:    input.service    || '',
  source:     input.source     || '',
  assignedTo: input.assignedTo || '',
  dealValue:  Number(input.dealValue) || 0
};

const success    = !!(input._name || input.reference_lead_id);
const isError    = !success;
const errorMsg   = isError ? 'Firestore write did not return a document path.' : '';
const statusCode = isError ? 500 : 200;

if (isError) {
  delete sd[`addlead_session_${telegramUserId}`];
}

return [{ json: { success, isError, errorMsg, statusCode, reference_lead_id, firestoreDocId, chatId, tenantId, data, telegramUserId } }];

