parameters.jsCode:
// ============================================================
// EVALUATE DUPLICATE  v2
//
// FIXES:
//   v1 — Object.keys check flagged empty passthrough items
//         (alwaysOutputData + continueRegularOutput passes the
//          upstream session object through on zero results,
//          which has many keys and was always treated as a match)
//   v2 — Only treat an item as a real Firestore match if it
//         contains at least one known lead field (email / fullName).
//         This correctly distinguishes 'no results' from 'found one'.
// ============================================================

const items = $input.all();
const upstream = $('Save or Prompt?').first().json;
const chatId   = upstream.chatId;
const tenantId = upstream.tenantId;
const data     = upstream.data;

// A real Firestore lead document always has at least email or fullName.
// Empty passthrough objects ({}) and session objects (which have action/step/chatId
// but NOT email/fullName as top-level Firestore fields) are excluded by this check.
const matchedDoc = items.find(i => {
  const j = i.json;
  return j && (j.email || j.fullName || j.name);
});

const isDuplicate = !!matchedDoc;

// Extract the existing lead's name for the warning message
const existingName =
  matchedDoc?.json?.fullName ||
  matchedDoc?.json?.name ||
  'an existing lead';

// Clear the session immediately on duplicate so the user is never
// stuck at step:saving — without this, every subsequent message
// re-enters the addlead branch and hits the same saving step again.
if (isDuplicate) {
  const sd = $getWorkflowStaticData('global');
  const msg = $('Telegram Trigger').first().json?.message;
  const telegramUserId = String(msg?.from?.id || '');
  delete sd[`addlead_session_${telegramUserId}`];
}

return [{ json: { isDuplicate, existingName, chatId, tenantId, data } }];

