    limit: 1
  }
}) }}

parameters.jsCode:
// ============================================================
// ADD LEAD — Step Router  (v3 — with TTL + input sanitisation)
// Fields validated against dashboard schema.
// Abandoned sessions expire after SESSION_TTL_MS (30 min).
// ============================================================

const sd = $getWorkflowStaticData('global');
const msg = $('Telegram Trigger').first().json?.message;
const telegramUserId = String(msg?.from?.id || '');
const chatId = String(msg?.chat?.id || msg?.from?.id || '');
const rawText = (msg?.text || '').trim();

// ── Sanitise helpers ─────────────────────────────────────────
// Strip to safe printable ASCII + common unicode letters, no HTML/script
function sanitise(val, maxLen) {
  return val
    .replace(/[<>"'`\\]/g, '')          // strip HTML/script chars
    .replace(/\s+/g, ' ')               // collapse whitespace
    .trim()
    .slice(0, maxLen);
}

function sanitiseName(val) {
  // Letters, spaces, hyphens, apostrophes, dots — no digits
  return val.replace(/[^a-zA-Z\u00C0-\u024F\s\-'.]/g, '').replace(/\s+/g, ' ').trim().slice(0, 100);
}

function sanitisePhone(val) {
  // Keep digits, +, -, (, ), spaces only
  return val.replace(/[^0-9+\-()\s]/g, '').replace(/\s+/g, ' ').trim().slice(0, 20);
}

function sanitiseCompany(val) {
  return sanitise(val, 100);
}

function sanitiseText(val, maxLen) {
  return sanitise(val, maxLen || 80);
}

function sanitisePerson(val) {
  // Names of people — letters, spaces, dots, hyphens only
  return val.replace(/[^a-zA-Z\u00C0-\u024F\s\-'.]/g, '').replace(/\s+/g, ' ').trim().slice(0, 60);
}

// ── Validation helpers ───────────────────────────────────────
function isSkip(val) { return val.toLowerCase() === 'skip'; }

function validateName(val) {
  const clean = sanitiseName(val);
  if (clean.length < 2) return { ok: false, msg: '⚠️ Name must be at least 2 characters and contain only letters.\n\nPlease send the lead\'s <b>full name</b>:' };
  return { ok: true, val: clean };
}

function validateEmail(val) {
  const clean = val.trim().toLowerCase();
  if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(clean)) return { ok: false, msg: '⚠️ Please enter a valid <b>email address</b>:\n(e.g. name@company.com)' };
  if (clean.length > 100) return { ok: false, msg: '⚠️ Email address is too long. Please enter a valid <b>email address</b>:' };
  return { ok: true, val: clean };
}

function validatePhone(val) {
  if (isSkip(val)) return { ok: true, val: '' };
  const clean = sanitisePhone(val);
  const digits = clean.replace(/\D/g, '');
  if (digits.length < 10 || digits.length > 15) return { ok: false, msg: '⚠️ Phone number must have 10–15 digits.\n\nPlease send a valid <b>phone number</b> (or type <i>skip</i>):' };
  return { ok: true, val: clean };
}

function validateCompany(val) {
  if (isSkip(val)) return { ok: true, val: '' };
  const clean = sanitiseCompany(val);
  if (clean.length < 1) return { ok: false, msg: '⚠️ Company name is invalid.\n\nPlease send the <b>company name</b> (or type <i>skip</i>):' };
  return { ok: true, val: clean };
}

function validateService(val) {
  const serviceMap = {
    '1': 'AI Strategy & Consulting',
    '2': 'Intelligent Automation',
    '3': 'Predictive Analytics',
    '4': 'General Enquiry',
    'ai strategy & consulting': 'AI Strategy & Consulting',
    'ai strategy': 'AI Strategy & Consulting',
    'intelligent automation': 'Intelligent Automation',
    'automation': 'Intelligent Automation',
    'predictive analytics': 'Predictive Analytics',
    'analytics': 'Predictive Analytics',
    'general enquiry': 'General Enquiry',
    'general': 'General Enquiry',
    'enquiry': 'General Enquiry',
  };
  const key = val.toLowerCase().trim();
  const mapped = serviceMap[key];
  if (!mapped) return { ok: false, msg: '⚠️ Please choose a valid service:\n\n1. AI Strategy &amp; Consulting\n2. Intelligent Automation\n3. Predictive Analytics\n4. General Enquiry\n\nReply with the number or service name:' };
  return { ok: true, val: mapped };
}

function validateSource(val) {
  if (isSkip(val)) return { ok: true, val: '' };
  const clean = sanitiseText(val, 80);
  if (clean.length < 1) return { ok: false, msg: '⚠️ Source is invalid.\n\nHow did this lead come in? (e.g. Website, LinkedIn, Referral — or type <i>skip</i>):' };
  return { ok: true, val: clean };
}

function validateAssignedTo(val) {
  if (isSkip(val)) return { ok: true, val: 'Unassigned' };
  const clean = sanitisePerson(val);
  if (clean.length < 2) return { ok: false, msg: '⚠️ Rep name must be at least 2 letters.\n\nWho should this lead be <b>assigned to</b>? (or type <i>skip</i>):' };
  return { ok: true, val: clean };
}

function validateDealValue(val) {
  if (isSkip(val)) return { ok: true, val: 0 };
  const raw = val.replace(/[^0-9.]/g, '') || '0';
  if (raw.length > 10) return { ok: false, msg: '⚠️ Deal value seems too large. Please enter a number up to 9,999,999 (or type <i>skip</i>):' };
  const num = parseFloat(raw) || 0;
  if (num < 0 || num > 9999999) return { ok: false, msg: '⚠️ Deal value must be between 0 and 9,999,999 (or type <i>skip</i>):' };
  return { ok: true, val: num };
}

// ── Get tenantId from user map cache ─────────────────────────
let tenantId = null;
try {
  const userMap = sd['user_tenant_map'] ? JSON.parse(sd['user_tenant_map']) : {};
  const rawEntry = userMap[telegramUserId] || null;
  tenantId = (rawEntry && typeof rawEntry === 'object') ? rawEntry.tenantId : rawEntry;
} catch { tenantId = null; }

const SESSION_KEY    = `addlead_session_${telegramUserId}`;
const SESSION_TTL_MS = 30 * 60 * 1000; // 30 minutes

let session = null;
try { session = sd[SESSION_KEY] ? JSON.parse(sd[SESSION_KEY]) : null; } catch { session = null; }

// ── TTL: expire abandoned sessions ───────────────────────────
if (session && session.createdAt) {
  const age = Date.now() - session.createdAt;
  if (age > SESSION_TTL_MS) {
    delete sd[SESSION_KEY];
    session = null;
    // Notify only if the user returned with a non-/addlead message
    if (!rawText.toLowerCase().startsWith('/addlead') && !rawText.toLowerCase().startsWith('/newlead')) {
      return [{ json: {
        action: 'prompt',
        step:   'expired',
        chatId,
        tenantId,
        message: '⏳ <b>Session expired.</b>\n\nYour previous lead entry timed out after 30 minutes of inactivity.\n\nType /addlead to start again.'
      }}];
    }
  }
}

// If user types /addlead fresh — reset and start
if (rawText.toLowerCase().startsWith('/addlead') || rawText.toLowerCase().startsWith('/newlead') || !session) {
  session = { step: 'name', data: {}, tenantId, chatId, telegramUserId, createdAt: Date.now() };
  sd[SESSION_KEY] = JSON.stringify(session);
  return [{ json: { action: 'prompt', step: 'name', chatId, tenantId,
    message: '➕ <b>Add New Lead</b>\n\nLet\'s get started! Please send me the lead\'s <b>full name</b>:' }}];
}

// Cancel anytime
if (['cancel', '/cancel'].includes(rawText.toLowerCase())) {
  delete sd[SESSION_KEY];
  return [{ json: { action: 'cancelled', chatId, tenantId,
    message: '❌ Lead creation cancelled.' }}];
}

const step = session.step;
const data = session.data;

// ── Process & validate current step ──────────────────────────

if (step === 'name') {
  const v = validateName(rawText);
  if (!v.ok) return [{ json: { action: 'prompt', step: 'name', chatId, tenantId, message: v.msg }}];
  data.fullName = v.val;
  session.step = 'email';
  sd[SESSION_KEY] = JSON.stringify(session);
  return [{ json: { action: 'prompt', step: 'email', chatId, tenantId,
    message: `✅ Name: <b>${v.val}</b>\n\nNow send me their <b>email address</b>:` }}];
}

if (step === 'email') {
  const v = validateEmail(rawText);
  if (!v.ok) return [{ json: { action: 'prompt', step: 'email', chatId, tenantId, message: v.msg }}];
  data.email = v.val;
  session.step = 'phone';
  sd[SESSION_KEY] = JSON.stringify(session);
  return [{ json: { action: 'prompt', step: 'phone', chatId, tenantId,
    message: `✅ Email: <b>${v.val}</b>\n\nNow send me their <b>phone number</b> (or type <i>skip</i>):` }}];
}

if (step === 'phone') {
  const v = validatePhone(rawText);
  if (!v.ok) return [{ json: { action: 'prompt', step: 'phone', chatId, tenantId, message: v.msg }}];
  data.phone = v.val;
  session.step = 'company';
  sd[SESSION_KEY] = JSON.stringify(session);
  return [{ json: { action: 'prompt', step: 'company', chatId, tenantId,
    message: '✅ Phone saved.\n\nWhat <b>company</b> are they from? (or type <i>skip</i>):' }}];
}

if (step === 'company') {
  const v = validateCompany(rawText);
  if (!v.ok) return [{ json: { action: 'prompt', step: 'company', chatId, tenantId, message: v.msg }}];
  data.company = v.val;
  session.step = 'service';
  sd[SESSION_KEY] = JSON.stringify(session);
  return [{ json: { action: 'prompt', step: 'service', chatId, tenantId,
    message: '✅ Company saved.\n\nWhat <b>service</b> are they interested in?\n\n1. AI Strategy &amp; Consulting\n2. Intelligent Automation\n3. Predictive Analytics\n4. General Enquiry\n\nReply with the number or type the name:' }}];
}

if (step === 'service') {
  const v = validateService(rawText);
  if (!v.ok) return [{ json: { action: 'prompt', step: 'service', chatId, tenantId, message: v.msg }}];
  data.service = v.val;
  session.step = 'source';
  sd[SESSION_KEY] = JSON.stringify(session);
  return [{ json: { action: 'prompt', step: 'source', chatId, tenantId,
    message: `✅ Service: <b>${v.val}</b>\n\nHow did this lead come in? <b>Source</b>\n(e.g. Website, LinkedIn, Referral, Cold Call — or type <i>skip</i>):` }}];
}

if (step === 'source') {
  const v = validateSource(rawText);
