  session.step = 'assignedTo';
  sd[SESSION_KEY] = JSON.stringify(session);
  return [{ json: { action: 'prompt', step: 'assignedTo', chatId, tenantId,
    message: '✅ Source saved.\n\nWho should this lead be <b>assigned to</b>?\n(Type the rep\'s name or type <i>skip</i> to leave unassigned):' }}];
}

if (step === 'assignedTo') {
  const v = validateAssignedTo(rawText);
  if (!v.ok) return [{ json: { action: 'prompt', step: 'assignedTo', chatId, tenantId, message: v.msg }}];
  data.assignedTo = v.val;
  session.step = 'dealValue';
  sd[SESSION_KEY] = JSON.stringify(session);
  return [{ json: { action: 'prompt', step: 'dealValue', chatId, tenantId,
    message: '✅ Assigned.\n\nWhat is the estimated <b>deal value</b>? (or type <i>skip</i>):' }}];
}

if (step === 'dealValue') {
  const v = validateDealValue(rawText);
  if (!v.ok) return [{ json: { action: 'prompt', step: 'dealValue', chatId, tenantId, message: v.msg }}];
  data.dealValue = v.val;
  session.step = 'confirm';
  sd[SESSION_KEY] = JSON.stringify(session);

  const summary = [
    '📋 <b>Lead Summary — Please Confirm</b>',
    '',
    `👤 <b>Name:</b> ${data.fullName}`,
    `📧 <b>Email:</b> ${data.email}`,
    `📞 <b>Phone:</b> ${data.phone || '—'}`,
    `🏢 <b>Company:</b> ${data.company || '—'}`,
    `🛠 <b>Service:</b> ${data.service || '—'}`,
    `🔗 <b>Source:</b> ${data.source || '—'}`,
    `👥 <b>Assigned To:</b> ${data.assignedTo}`,
    `💰 <b>Deal Value:</b> ${(data.dealValue || 0).toLocaleString('en-IN')}`,
    `📌 <b>Status:</b> New`,
    '',
    'Type <b>yes</b> to save or <b>no</b> to cancel.'
  ].join('\n');

  return [{ json: { action: 'prompt', step: 'confirm', chatId, tenantId, data,
    message: summary }}];
}

if (step === 'confirm') {
  if (['yes', 'y', 'save', 'confirm'].includes(rawText.toLowerCase())) {
    session.step = 'saving';
    sd[SESSION_KEY] = JSON.stringify(session);
    return [{ json: { action: 'save', step: 'saving', chatId, tenantId, data: session.data }}];
  } else {
    delete sd[SESSION_KEY];
    return [{ json: { action: 'cancelled', chatId, tenantId,
      message: '❌ Lead creation cancelled. Type /addlead to start again.' }}];
  }
}

// Fallback
delete sd[SESSION_KEY];
return [{ json: { action: 'prompt', step: 'name', chatId, tenantId,
  message: '➕ <b>Add New Lead</b>\n\nPlease send me the lead\'s <b>full name</b>:' }}];

