// ============================================================
// QUERY PROCESSOR  —  Local AI Agent Replacement v1.3
// Fixes:
//   v1.1 — deal-value routing, new/won/lost false triggers, tier count accuracy
//   v1.2 — industry/source/service filtering added to SHOW command
//   v1.3 — BUG FIX: short aggregation keys (1-2 chars) caused false matches
//   v1.4 — BUG FIX: status filter + "all" keyword no longer capped at 10
//   v1.5 — BUG FIX: "deals values" phrasing not recognized; tier ignored in deal-value queries
//           e.g. service key "e" matching inside "Healthcare", rep "ds" inside "leads"
//           Fix: require minimum 3-char key AND whole-word boundary matching
// ============================================================

function optionC(title, dataObj, total, icon) {
  const sorted = Object.entries(dataObj).filter(([,v]) => v > 0).sort((a,b) => b[1]-a[1]);
  const C1 = 7, C2 = 26, C3 = 8;
  const sep = '-'.repeat(C1 + C2 + C3);
  const hdr = pad('Count', C1) + pad('Name', C2) + rpad('Percent', C3);
  const rows = sorted.map(([k, v]) => {
    const pctVal = Math.round(v / total * 100);
    return pad(v, C1) + pad(k, C2) + rpad(pctVal + '%', C3);
  }).join('\n');
  const totRow = pad(total, C1) + pad('Total', C2) + rpad('100%', C3);
  const table = hdr + '\n' + sep + '\n' + rows + '\n' + sep + '\n' + totRow;
  return icon + ' <b>' + title + '</b>\n<pre>' + table + '</pre>';
}

const d = $input.first().json;

if (d.isRefreshCommand || d.isBlocked) {
  return [{ json: d }];
}

if (!d.leadsPayload) {
  return [{ json: { output: '⚠️ No data available. Please try again.' } }];
}

let p;
try { p = JSON.parse(d.leadsPayload); } catch {
  return [{ json: { output: '⚠️ Data parse error. Please type refresh and try again.' } }];
}

if (!p.success) {
  return [{ json: { output: `⚠️ CRM error: ${p.error || 'Unknown error'}` } }];
}

// ── Helpers ──────────────────────────────────────────────────────────────────
const userMsg = ($('Telegram Trigger').first().json?.message?.text || '').toLowerCase().trim();
const leads   = Array.isArray(p.leads) ? p.leads : [];
const agg     = p.aggregations || {};
const meta    = p._meta || {};

const fmt  = n => (n || 0).toLocaleString('en-IN');
const pct  = (n, t) => t ? `${((n / t) * 100).toFixed(1)}%` : '0%';
const cur  = v => `${Number(v || 0).toLocaleString('en-IN')}`;
function titleCase(s) { return (s || '').replace(/\b\w/g, c => c.toUpperCase()); }
function pad(s, n)  { return String(s).padEnd(n); }
function rpad(s, n) { return String(s).padStart(n); }
function esc(s)     { return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }

const is = (...kws) => kws.some(k => userMsg.includes(k));

// ── Safe keyword matcher ──────────────────────────────────────────────────────
// Prevents short keys (≤2 chars) from matching inside longer words.
// Uses word-boundary matching for keys 3+ chars long.
// e.g. key "e" will NOT match inside "Healthcare"; key "healthcare" WILL match.
function safeMatch(userMsg, keys) {
  return keys.find(k => {
    const kl = k.toLowerCase().trim();
    if (kl.length <= 2) return false; // skip dangerously short keys
    // word-boundary check: the key must not be flanked by word characters
    const escaped = kl.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    const re = new RegExp('(?<![a-z0-9])' + escaped + '(?![a-z0-9])', 'i');
    return re.test(userMsg);
  });
}

// ── 1. PIPELINE / SUMMARY ────────────────────────────────────────────────────
if (is('pipeline', 'summary', 'overview')) {
