  const stageLines = stages.filter(s => statuses[s] > 0)
    .map(s => `  • ${titleCase(s)}: ${statuses[s]} (${pct(statuses[s], total)})`).join('\n');
  const assignees = agg.assignedTo || {};
  const topRepEntry = Object.entries(assignees).filter(([k]) => k.toLowerCase() !== 'unassigned').sort((a,b)=>b[1]-a[1])[0];
  const topRep = topRepEntry ? `${topRepEntry[0]} (${topRepEntry[1]} leads)` : 'N/A';
  const sources = agg.source || {};
  const topSrcEntry = Object.entries(sources).sort((a,b)=>b[1]-a[1])[0];
