}

// ── 2. HOW MANY / COUNT ──────────────────────────────────────────────────────
if (is('how many', 'count', 'total')) {
  if (is('deal value', 'deal values', 'pipeline value', 'revenue', 'top deal', 'highest deal', 'largest deal', 'top value', 'highest value')) {
    const requestedNMatch = userMsg.match(/\b(\d+)\b/);
