    const sept = '-'.repeat(C1t + C2t + C3t);
    const hdrt = pad('Count', C1t) + pad('Name', C2t) + rpad('Percent', C3t);
    const rowst = tierRows.map(([name, cnt]) => pad(cnt, C1t) + pad(name, C2t) + rpad(Math.round(cnt/total*100) + '%', C3t)).join('\n');
    const totRowt = pad(total, C1t) + pad('Total', C2t) + rpad('100%', C3t);
