  }
  const assignees = agg.assignedTo || {};
  const repKeys = Object.keys(assignees).map(k => k.toLowerCase());
  const matchedRep = safeMatch(userMsg, repKeys);
  if (matchedRep) {
    const displayName = Object.keys(assignees).find(k => k.toLowerCase() === matchedRep.toLowerCase());
