  }
  const statuses = agg.status || {};
  const knownStatuses = ['new','contacted','qualified','proposal sent','negotiation','won','lost','discovery call'];
  const matchedStatus = knownStatuses.find(s => userMsg.includes(s));
  if (matchedStatus) {
    const count = statuses[matchedStatus] || 0;
    const total = p.totalAll || p.total || 0;
    return [{ json: { output: `📋 There are <b>${count}</b> leads in <b>${titleCase(matchedStatus)}</b> (${pct(count, total)} of total).\n\n${p.dataFooter}` }}];
  }
  const repLines = Object.entries(agg.assignedTo || {}).sort((a,b)=>b[1]-a[1]).map(([n,c]) => `  • ${n}: ${c}`).join('\n');
  return [{ json: { output:
    `📊 You have <b>${fmt(p.totalAll || p.total)}</b> total leads in your CRM.\n\n<b>By Rep:</b>\n${repLines}\n\n${p.dataFooter}`
  }}];
}

