    const totRow = pad('', C1) + pad(totalDeal > 0 ? commaFmt(totalDeal) : '—', C2) + pad('', C3);
    const table = hdr + '\n' + sep + '\n' + (tableRows.length ? tableRows.join('\n') + '\n' + sep + '\n' + totRow : 'No leads found.');

    const dataFooterClean = p.dataFooter.replace(/^_\((.+)\)_$/, '$1');
    const header = '<b>👤 ' + displayName + '</b> — ' + count + ' lead' + (count !== 1 ? 's' : '') + ' (' + pct(count, total) + ' of total)';
    const formatted = header + '\n<pre>' + table + '</pre>\n<i>(' + esc(dataFooterClean) + ')</i>';
    return [{ json: { isRefreshCommand: true, formatted } }];
