// ── 8. SOURCE / INDUSTRY / SERVICE — breakdown OR specific-value listing ─────
if (is('source', 'industry', 'service')) {
  const field = is('source') ? 'source' : is('industry') ? 'industry' : 'service';
  const fieldKeys = Object.keys(agg[field] || {});
