// ============================================================
// RESET FULL CACHE  v2.2
// Super-admin command: nukes ALL cache — tenant data, user map,
// per-user timestamps, and refresh cooldowns.
// After reset, every user hits Firebase once to rebuild their entry.
//
// FIXES:
//   v2.0 — Explicitly excludes 'umap_ts_' keys from deletion
//   v2.1 — Reports deleted key categories for easier debugging
//   v2.2 — NOW also deletes 'umap_ts_*' per-user timestamps.
//           Previously timestamps survived reset, causing logical
//           inconsistency where map blob was gone but timestamps
//           remained. Full purge is cleaner and correct.
// ============================================================

const sd = $getWorkflowStaticData('global');
const keys = Object.keys(sd);

const nukedTenant    = [];
const nukedUserMap   = [];
const nukedTimestamp = [];
const nukedSession   = [];
const skipped        = [];

for (const key of keys) {
  if (key.startsWith('tenant_')) {
    delete sd[key];
    nukedTenant.push(key);
  } else if (key === 'user_tenant_map') {
    delete sd[key];
    nukedUserMap.push(key);
  } else if (key.startsWith('umap_ts_')) {
    // v2.2: also wipe per-user timestamps — map blob is gone so timestamps are stale
    delete sd[key];
    nukedTimestamp.push(key);
  } else if (key.startsWith('lastCacheSource') || key.startsWith('last_refresh_')) {
    delete sd[key];
    nukedUserMap.push(key);
  } else {
    // addlead_session_* intentionally preserved — active wizard sessions survive reset
    skipped.push(key);
  }
}

const totalNuked = nukedTenant.length + nukedUserMap.length + nukedTimestamp.length + nukedSession.length;

return [{
  json: {
    success:             true,
    message:             `Cache fully purged. Deleted ${totalNuked} keys.`,
    deletedTenantKeys:   nukedTenant,
    deletedUserMapKeys:  nukedUserMap,
    deletedTimestamps:   nukedTimestamp,
    skippedKeys:         skipped,
    totalDeleted:        totalNuked
  }
}];

// ============================================================
// READ SESSION CACHE — Tenant-Scoped  v2.1
// TTL: 4 hours (240 minutes)
//
// Cache bust triggers (ANY one causes a fresh Firestore fetch):
//   1. No data exists for tenant
//   2. TTL > 60 minutes
//   3. User message contains refresh keyword
//   4. Cached lead count != stored Firestore count (data changed)
//
// NOTE: 'reset' and 'resetevodesk' are intentionally excluded from
// refresh keywords — resetevodesk is a super-admin command handled
// exclusively by Command Router / Lookup User Role / Is Admin? chain.
//
// FIXES:
//   v2.0 — Added _sdKeyCount diagnostic output on every path
//           (always 0 = static data not persisting = queue-mode issue)
//   v2.1 — Stale-key cleanup on cache miss now also removes KEY_TOP_DEALS
// ============================================================

const sd = $getWorkflowStaticData('global');

const safeparse = (val, fallback) => {
  try { return JSON.parse(val); } catch { return fallback; }
};

// ── DIAGNOSTIC ────────────────────────────────────────────────────────────
// _sdKeyCount is the single most important signal for diagnosing cache issues:
//   - Always 0 across multiple executions → static data is NOT persisting.
//     Root cause: n8n queue mode (EXECUTIONS_MODE=queue) with multiple workers,
//     or an n8n restart between executions.
//   - Non-zero but cache still misses → TTL expired or keys were deleted by reset.
const _sdKeyCount = Object.keys(sd).length;

// ── Resolve tenantId ──────────────────────────────────────────────────────
const tenantId = $input.first().json?.tenantId || null;

if (!tenantId) {
  return [{
    json: {
      cacheExists: false,
      tenantId:    null,
      error:       'tenantId could not be resolved. Cannot proceed.',
      fatalError:  true,
      _sdKeyCount
    }
  }];
}

// ── Keys ─────────────────────────────────────────────────────────────────
const KEY_PREFIX      = `tenant_${tenantId}`;
const KEY_CACHED_AT   = `${KEY_PREFIX}_cachedAt`;
const KEY_LEADS       = `${KEY_PREFIX}_leadsCache`;
const KEY_AGGREGATION = `${KEY_PREFIX}_aggregationSnapshot`;
const KEY_TOTAL       = `${KEY_PREFIX}_leadTotal`;
const KEY_TOTAL_ALL   = `${KEY_PREFIX}_totalAll`;
const KEY_DEAL_VALUE  = `${KEY_PREFIX}_totalDealValue`;
const KEY_FILTERS     = `${KEY_PREFIX}_filtersApplied`;
const KEY_FS_COUNT    = `${KEY_PREFIX}_firestoreCount`;
const KEY_TOP_DEALS   = `${KEY_PREFIX}_topDealsByRep`;

// ── TTL check ────────────────────────────────────────────────────────────
const AGE_LIMIT = 4 * 60 * 60 * 1000;
const cachedAt  = sd[KEY_CACHED_AT] ? Number(sd[KEY_CACHED_AT]) : 0;
const ageMs     = Date.now() - cachedAt;
const isExpired = !cachedAt || ageMs > AGE_LIMIT;

// ── Data presence ────────────────────────────────────────────────────────
const hasData = !!sd[KEY_LEADS] && !!sd[KEY_AGGREGATION];

// ── Manual refresh keyword detection ─────────────────────────────────────
const userMsg = $('Telegram Trigger').item.json?.message?.text || '';
const REFRESH_MIN_AGE_MS = 20 * 60 * 1000;

const isRefreshKeyword = ['refresh', 'reload', 'update data', 'clear cache']
  .some(kw => userMsg.toLowerCase().includes(kw));

// If user asks refresh but cache is younger than 20 min → block
if (isRefreshKeyword && hasData && ageMs < REFRESH_MIN_AGE_MS) {
  const waitMin = Math.ceil((REFRESH_MIN_AGE_MS - ageMs) / 60000);
  return [{ json: {
    cacheExists:    true,
    tenantId,
    cacheAgeMin:    Math.floor(ageMs / 60000),
    success:        true,
    source:         'cache',
    filters:        safeparse(sd[KEY_FILTERS],     {}),
    total:          Number(sd[KEY_TOTAL]           || 0),
    totalAll:       Number(sd[KEY_TOTAL_ALL]       || 0),
    totalDealValue: Number(sd[KEY_DEAL_VALUE]      || 0),
    aggregations:   safeparse(sd[KEY_AGGREGATION], {}),
    topDealsByRep:  safeparse(sd[KEY_TOP_DEALS],   {}),
    leads:          safeparse(sd[KEY_LEADS],        []),
    refreshBlocked: true,
    _sdKeyCount,
    refreshBlockMsg: `\uD83D\uDEAB <b>Refresh not allowed yet.</b>\n\n\u23F1 Cache is only <b>${Math.floor(ageMs / 60000)} min old</b> \u2014 please wait <b>${waitMin} more min</b>.\n<i>Refresh is allowed once cache is 20+ min old.</i>`
  }}];
}

const forceRefresh = isRefreshKeyword;
const countMismatch = false;

const bustReasons = [];
if (!hasData)      bustReasons.push('no_data');
if (isExpired)     bustReasons.push(`ttl_exceeded_${Math.floor(ageMs/60000)}min`);
if (forceRefresh)  bustReasons.push('force_refresh_keyword');
if (countMismatch) bustReasons.push('count_mismatch');

const cacheValid = bustReasons.length === 0;

if (cacheValid) {
  return [{
    json: {
      cacheExists:    true,
      tenantId,
      cacheAgeMin:    Math.floor(ageMs / 60000),
      success:        true,
      source:         'cache',
      filters:        safeparse(sd[KEY_FILTERS],     {}),
      total:          Number(sd[KEY_TOTAL]           || 0),
      totalAll:       Number(sd[KEY_TOTAL_ALL]       || 0),
      totalDealValue: Number(sd[KEY_DEAL_VALUE]      || 0),
      aggregations:   safeparse(sd[KEY_AGGREGATION], {}),
      topDealsByRep:  safeparse(sd[KEY_TOP_DEALS],   {}),
      leads:          safeparse(sd[KEY_LEADS],        []),
      _sdKeyCount
    }
  }];
}

// Cache miss — clear stale keys atomically before downstream fetch
delete sd[KEY_LEADS];
delete sd[KEY_AGGREGATION];
delete sd[KEY_CACHED_AT];
delete sd[KEY_TOTAL];
delete sd[KEY_TOTAL_ALL];
delete sd[KEY_DEAL_VALUE];
delete sd[KEY_FILTERS];
delete sd[KEY_FS_COUNT];
delete sd[KEY_TOP_DEALS]; // FIX v2.1: also clear top deals on miss

return [{
  json: {
    cacheExists:   false,
    tenantId,
    forceRefresh,
    bustReasons,
    cacheAgeMin:   cachedAt ? Math.floor(ageMs / 60000) : null,
    _sdKeyCount
  }
}];

// ============================================================
// AGGREGATE + SAVE TO CACHE — Tenant-Scoped  [FIXED v2]
//
// FIXES APPLIED:
//   1. tenantId scans ALL items for tenant_id / tenantId (not just first).
//   2. Processes $input.all() — works correctly now that Detect Summary Error
//      passes all items through instead of collapsing to 1.
//   3. Skips error/passthrough items mixed in (ok:true, _isFirebaseError:true).
// ============================================================

try {

  const allItems = $input.all();

  // ── FIX: scan all items for tenantId, not just first ──────────────────────
  let tenantId = null;
  for (const it of allItems) {
    const d = it?.json || {};
    const t = d.tenantId || d.tenant_id || null;
    if (t) { tenantId = t; break; }
  }
  if (!tenantId) {
    tenantId = $('Read Session Cache').first().json?.tenantId || null;
  }

  if (!tenantId) {
    return [{ json: {
      success: false,
      error:   'tenantId missing — cannot write cache.',
      total: 0, totalAll: 0, aggregations: {}, leads: []
    }}];
  }

  const KEY_PREFIX      = `tenant_${tenantId}`;
  const KEY_CACHED_AT   = `${KEY_PREFIX}_cachedAt`;
  const KEY_LEADS       = `${KEY_PREFIX}_leadsCache`;
  const KEY_AGGREGATION = `${KEY_PREFIX}_aggregationSnapshot`;
  const KEY_TOTAL       = `${KEY_PREFIX}_leadTotal`;
  const KEY_TOTAL_ALL   = `${KEY_PREFIX}_totalAll`;
  const KEY_DEAL_VALUE  = `${KEY_PREFIX}_totalDealValue`;
  const KEY_FILTERS     = `${KEY_PREFIX}_filtersApplied`;
  const KEY_FS_COUNT    = `${KEY_PREFIX}_firestoreCount`;
  const KEY_VERSION     = `${KEY_PREFIX}_cacheVersion`;
  const KEY_TOP_DEALS   = `${KEY_PREFIX}_topDealsByRep`;

  const AGGREGATION_FIELDS = ['status', 'service', 'industry', 'assignedTo', 'source', 'company'];
  const VALID_STATUSES = new Set([
    'new', 'contacted', 'discovery call', 'qualified', 'proposal sent',
    'negotiation', 'won', 'lost'
  ]);

  if (!allItems || allItems.length === 0) {
    return [{ json: {
      success: false, tenantId,
      error: 'No items returned from Firestore',
      total: 0, totalAll: 0, aggregations: {}, leads: []
    }}];
  }

  // ── GUARD: Reject non-Firestore input (Firebase 429 passthrough) ──────────
  const hasRealLeads = allItems.some(it => {
    const d = it?.json || {};
    return !!(d.tenant_id || d._name || d._id || d.name || d.email || d.status);
  });
  if (!hasRealLeads) {
    return [{ json: {
      success: false,
      tenantId,
      error: 'Firebase fetch failed (passthrough input — likely 429). Cache NOT updated.',
      _cachePreserved: true,
      total: 0, totalAll: 0, aggregations: {}, leads: []
    }}];
  }

  // ── Process ALL items ──────────────────────────────────────────────────────
  const leads = allItems
    .map((item, idx) => {
      const d = item?.json;
      if (!d || typeof d !== 'object') return null;
      // Skip error/passthrough items that may be mixed in
      if (d._isFirebaseError === true || d.ok === true) return null;
      const recordTenant = d.tenant_id || d.tenantId || '';
      if (recordTenant && recordTenant !== tenantId) return null;
      let createdAt = null;
      if (d.createdAt) {
        const p = new Date(d.createdAt);
        createdAt = isNaN(p.getTime()) ? null : p.toISOString();
      }
      return {
        leadId:            d.leadId      || d._id         || '',
        tenantId:          recordTenant  || tenantId,
        name:              d.name        || d.fullName    || '',
        company:           d.company     || d.companyName || '',
        email:             d.email       || '',
        phone:             d.phone       || '',
        status:            (d.status     || 'new').toLowerCase().trim(),
        service:           (d.service    || 'unknown').toLowerCase().trim(),
        industry:          (d.industry   || 'unknown').toLowerCase().trim(),
        assignedTo:        (d.assignedTo || 'unassigned').toLowerCase().trim(),
        assignedToDisplay: (d.assignedTo || 'Unassigned').trim(),
        source:            (d.source     || 'unknown').toLowerCase().trim(),
        dealValue:         Number(d.dealValue) || 0,
        followup:          d.followup    || null,
        createdAt
      };
    })
    .filter(Boolean);

  const aggregations = {};
  for (const f of AGGREGATION_FIELDS) aggregations[f] = {};
  for (const s of VALID_STATUSES) aggregations.status[s] = 0;
  aggregations.status.__other__ = 0;

  for (const lead of leads) {
    for (const field of AGGREGATION_FIELDS) {
      const value = field === 'assignedTo'
        ? (lead.assignedToDisplay || lead.assignedTo || 'Unassigned')
        : (lead[field] || 'unknown');
      if (field === 'status') {
        VALID_STATUSES.has(value)
          ? aggregations.status[value]++
          : aggregations.status.__other__++;
      } else {
        aggregations[field][value] = (aggregations[field][value] || 0) + 1;
      }
    }
  }

  const topDealsByRep = {};
  for (const lead of leads) {
    const rep = lead.assignedToDisplay || lead.assignedTo || 'Unassigned';
    if (!topDealsByRep[rep]) topDealsByRep[rep] = [];
    topDealsByRep[rep].push({
      name:      lead.name,
      company:   lead.company,
      dealValue: lead.dealValue || 0,
      status:    lead.status
    });
  }
  for (const rep of Object.keys(topDealsByRep)) {
    topDealsByRep[rep].sort((a, b) => b.dealValue - a.dealValue);
  }

  // Active pipeline only — exclude Won and Lost
  const EXCLUDED_STATUSES = new Set(['won', 'lost']);
  const totalDealValue = leads
    .filter(l => !EXCLUDED_STATUSES.has(l.status))
    .reduce((s, l) => s + (l.dealValue || 0), 0);
  const totalDealValueAll = leads.reduce((s, l) => s + (l.dealValue || 0), 0);
  const wonDealValue  = leads.filter(l => l.status === 'won').reduce((s, l) => s + (l.dealValue || 0), 0);
  const lostDealValue = leads.filter(l => l.status === 'lost').reduce((s, l) => s + (l.dealValue || 0), 0);
  const writtenAt      = Date.now();
  const version        = `v_${writtenAt}`;

  const sd = $getWorkflowStaticData('global');
  sd[KEY_VERSION]     = version;
  sd[KEY_CACHED_AT]   = String(writtenAt);
  sd[KEY_FS_COUNT]    = String(leads.length);
  sd[KEY_TOTAL]       = String(leads.length);
  sd[KEY_TOTAL_ALL]   = String(leads.length);
  sd[KEY_DEAL_VALUE]  = String(totalDealValue);
  sd[KEY_FILTERS]     = JSON.stringify({});
  sd[KEY_AGGREGATION] = JSON.stringify({
    status:     aggregations.status,
    service:    aggregations.service,
    industry:   aggregations.industry,
    assignedTo: aggregations.assignedTo,
    source:     aggregations.source,
    company:    aggregations.company
  });
  sd[KEY_TOP_DEALS]   = JSON.stringify(topDealsByRep);
  sd[KEY_LEADS]       = JSON.stringify(leads);

  return [{ json: {
    success:        true,
    tenantId,
    source:         'firestore',
    cacheVersion:   version,
    refreshedAt:    new Date(writtenAt).toISOString(),
    filters:        {},
    total:          leads.length,
    totalAll:       leads.length,
    totalDealValue,
    totalDealValueAll,
    wonDealValue,
    lostDealValue,
    aggregations,
    topDealsByRep,
    leads
  }}];

} catch (err) {
  return [{ json: {
    success:      false,
    error:        err.message || 'Unknown aggregation error',
    total:        0, totalAll: 0, aggregations: {}, leads: []
  }}];
}

// ============================================================
// SLIM PAYLOAD  —  v10 (proper dual-path data source)
// email+10, phone+15, company+10, linkedin+10, service+10
// Stage: New=5,Contacted=15,Discovery Call=25,Qualified=40,
//        Proposal Sent=55,Negotiation=70,Won=100,Lost=0 (default 5)
// Deal: +1 per 5000, max +20. Cap 100.
// Tier: HOT>=60, WARM>=35, COLD<35
// ============================================================

// ── Data source: use Firestore output on cache miss, Read Session Cache on cache hit
// $input.source = 'firestore' when coming from Aggregate+Save to Cache (cache miss path)
// $input.source = 'cache' (or absent) when coming from Cache Exists? True branch
const _input = $input.first().json;
const data = _input.source === 'firestore'
  ? _input
  : $('Read Session Cache').first().json;

if (data.fatalError || data.success === false) {
  return [{ json: data }];
}

const userQuery = ($('Telegram Trigger').first().json?.message?.text || '').toLowerCase();

function computeScore(l) {
  let s = 0;
  // Treat empty-string placeholders and 'unknown' as absent
  const has = v => v && v !== 'unknown' && v !== 'unassigned';
  if (has(l.email))    s += 10;
  if (has(l.phone))    s += 15;
  if (has(l.company))  s += 10;
  if (has(l.linkedin)) s += 10;
  const stageScore = {
    'new': 5, 'contacted': 15, 'discovery call': 25,
    'qualified': 40, 'proposal sent': 55, 'negotiation': 70,
    'won': 100, 'lost': 0
  };
  s += stageScore[(l.status || '').toLowerCase().trim()] ?? 5;
  if (has(l.service)) s += 10;
  if (l.dealValue) {
    const val = Number(String(l.dealValue).replace(/[^0-9.]/g, '')) || 0;
    s += Math.min(20, Math.floor(val / 5000));
  }
  return Math.min(100, s);
}

function scoreTier(score) {
  if (score >= 60) return { tier: 'HOT',  emoji: '🔴' };
  if (score >= 35) return { tier: 'WARM', emoji: '🟡' };
  return             { tier: 'COLD', emoji: '🔵' };
}

// ── 1. Number extractor ───────────────────────────────────
const requestedNMatch = userQuery.match(/\b(\d+)\b/);
const requestedN = requestedNMatch ? parseInt(requestedNMatch[1], 10) : null;

// ── 2. Assignee filter — dynamic from cache (no hardcoded names) ─────
// Build a token→fullName map from aggregations.assignedTo.
// Each display name (e.g. "Chandrashekhar Dhere") is split into individual
// word tokens (["chandrashekhar", "dhere"]) so partial name queries like
// "leads assigned to shekhar" or "leads for chandrashekhar" both work.
// Minimum 3 chars per token to avoid noise words.
const _assigneeAgg = data.aggregations?.assignedTo || {};

// Map: lowercased token → lowercased full name (for lead filtering)
const _assigneeTokenMap = {};
for (const displayName of Object.keys(_assigneeAgg)) {
  const full = displayName.toLowerCase().trim();
  if (full === 'unassigned') continue;
  // Add the full name as a token
  if (full.length >= 3) _assigneeTokenMap[full] = full;
  // Add each word as a token too
  for (const word of full.split(/\s+/)) {
    if (word.length >= 3) _assigneeTokenMap[word] = full;
  }
}
// Include unassigned explicitly
_assigneeTokenMap['unassigned'] = 'unassigned';

// Word-boundary safe match against query
const _assigneeWordMatch = (key, q) => {
  if (key.length < 3) return false;
  const escaped = key.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  return new RegExp('(?<![a-z])' + escaped + '(?![a-z])', 'i').test(q);
};

// Find which token matches the query, then resolve to full name for filtering
const _matchedToken = Object.keys(_assigneeTokenMap).find(t => _assigneeWordMatch(t, userQuery));
// assigneeMatch = the full lowercased name used to filter leads array
const assigneeMatch = _matchedToken ? _assigneeTokenMap[_matchedToken] : null;

// ── 3. Status filter ──────────────────────────────────────
const knownStatuses = ['new', 'contacted', 'qualified', 'proposal', 'negotiation', 'won', 'lost', 'discovery call'];
const statusMatch = knownStatuses.find(s => userQuery.includes(s));

// ── 4. Service filter ─────────────────────────────────────
const knownServices = [
  'intelligent automation', 'predictive analytics', 'ai strategy',
  'general enquiry', 'general inquiry',   // both spellings
  'custom development', 'consulting', 'training', 'support', 'implementation',
  'data analytics', 'cloud migration', 'cybersecurity', 'digital transformation'
];
const serviceMatch = knownServices.find(s => userQuery.includes(s));

// ── 4b. Industry filter (alias map) ─────────────────────────────────
const industryAliases = {
  'healthcare':             'healthcare & life sciences',
  'health':                 'healthcare & life sciences',
  'pharma':                 'pharmaceuticals & biotechnology',
  'pharmaceuticals':        'pharmaceuticals & biotechnology',
  'biotech':                'pharmaceuticals & biotechnology',
  'banking':                'banking & financial services (bfsi)',
  'bfsi':                   'banking & financial services (bfsi)',
  'fintech':                'banking & financial services (bfsi)',
  'fmcg':                   'fmcg / consumer goods',
  'consumer goods':         'fmcg / consumer goods',
  'retail':                 'retail & e-commerce',
  'e-commerce':             'retail & e-commerce',
  'ecommerce':              'retail & e-commerce',
  'information technology': 'information technology (it & software)',
  'software':               'information technology (it & software)',
  'logistics':              'logistics & supply chain',
  'supply chain':           'logistics & supply chain',
  'manufacturing':          'manufacturing',
  'mfg':                    'manufacturing',
  'insurance':              'insurance',
  'travel':                 'travel & hospitality',
  'hospitality':            'travel & hospitality',
  'energy':                 'energy & utilities',
  'utilities':              'energy & utilities',
  'education':              'education & edtech',
  'edtech':                 'education & edtech',
  'agriculture':            'agriculture & agritech',
  'agritech':               'agriculture & agritech',
  'media':                  'media & entertainment',
  'entertainment':          'media & entertainment',
  'real estate':            'real estate & construction',
  'construction':           'real estate & construction',
  'consulting':             'consulting & professional services',
};
const industryKeyword = Object.keys(industryAliases).find(k => userQuery.includes(k));
const industryTarget  = industryKeyword ? industryAliases[industryKeyword] : null;

// ── 4c. Source filter ─────────────────────────────────────────────────────
const knownSources = ['referral', 'cold call', 'website', 'linkedin', 'email', 'partner', 'event', 'inbound', 'outbound'];
const sourceMatch  = knownSources.find(s => userQuery.includes(s));

// ── 5. Intent flags ───────────────────────────────────────
const isDealValueQuery = (
  userQuery.includes('top deal') || userQuery.includes('deal value') ||
  userQuery.includes('deals value') || userQuery.includes('deal values') ||
  userQuery.includes('deals values') || userQuery.includes('top deals') ||
  userQuery.includes('by value') || userQuery.includes('biggest deal') ||
  userQuery.includes('biggest deals') ||
  userQuery.includes('highest deal') || userQuery.includes('largest deal') ||
  userQuery.includes('top value') || userQuery.includes('highest value') ||
  userQuery.includes('revenue')
);
const isRecencyQuery = (
  userQuery.includes('latest') || userQuery.includes('newest') ||
  userQuery.includes('most recent') || userQuery.includes('recent')
);
const isOldestQuery = userQuery.includes('oldest') || userQuery.includes('earliest');

// ── 6. Tier filter ────────────────────────────────────────
const mentionedTiers = [
  userQuery.includes('hot')  ? 'HOT'  : null,
  userQuery.includes('warm') ? 'WARM' : null,
  userQuery.includes('cold') ? 'COLD' : null
].filter(Boolean);
// If multiple tiers mentioned, treat as "show all tiers" — don't filter to one
const filterTier = mentionedTiers.length === 1 ? mentionedTiers[0] : null;
const multiTier  = mentionedTiers.length > 1;

// ── 7. Apply filters ──────────────────────────────────────
let leads = Array.isArray(data.leads) ? data.leads : [];

// Use strict equality for assignee — 'shekhar' must not match inside 'chandrashekhar dhere'
if (assigneeMatch) leads = leads.filter(l => (l.assignedTo || '').toLowerCase() === assigneeMatch);
if (statusMatch)   leads = leads.filter(l => (l.status || '').toLowerCase().includes(statusMatch));
if (serviceMatch)  leads = leads.filter(l => (l.service || '').toLowerCase().includes(serviceMatch));
if (sourceMatch)   leads = leads.filter(l => (l.source  || '').toLowerCase().includes(sourceMatch));
if (industryKeyword) leads = leads.filter(l => (l.industry || '').toLowerCase().trim().includes(industryKeyword));

// ── 8. Company filter ─────────────────────────────────────
const allCompanies = [...new Set(leads.map(l => (l.company || '').toLowerCase()).filter(c => c.length > 3))];
const companyWordRe = (c) => new RegExp('(?<![a-z])' + c.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '(?![a-z])', 'i');
const companyMatch = allCompanies.find(c => companyWordRe(c).test(userQuery));
if (companyMatch) leads = leads.filter(l => (l.company || '').toLowerCase() === companyMatch);

// ── 9. Score ──────────────────────────────────────────────
leads = leads.map(l => {
  const score           = computeScore(l);
  const { tier, emoji } = scoreTier(score);
  return { ...l, score, tier, emoji };
});

// ── 10. Tier counts BEFORE filter ────────────────────────
const tierCount = {
  HOT:  leads.filter(l => l.tier === 'HOT').length,
  WARM: leads.filter(l => l.tier === 'WARM').length,
  COLD: leads.filter(l => l.tier === 'COLD').length
};

// ── 11. Tier filter ───────────────────────────────────────
if (filterTier) leads = leads.filter(l => l.tier === filterTier);

// ── 12. Sort ──────────────────────────────────────────────
if (isDealValueQuery) {
  // Exclude closed deals from deal value ranking — active pipeline only
  leads = leads.filter(l => l.status !== 'won' && l.status !== 'lost');
  leads = leads.slice().sort((a, b) => (b.dealValue || 0) - (a.dealValue || 0));
} else if (isOldestQuery) {
  leads = leads.slice().sort((a, b) => {
    const da = a.createdAt ? new Date(a.createdAt).getTime() : Infinity;
    const db = b.createdAt ? new Date(b.createdAt).getTime() : Infinity;
    return da - db;
  });
} else if (isRecencyQuery) {
  leads = leads.slice().sort((a, b) => {
    const da = a.createdAt ? new Date(a.createdAt).getTime() : 0;
    const db = b.createdAt ? new Date(b.createdAt).getTime() : 0;
    return db - da;
  });
}

// ── 13. Slice ─────────────────────────────────────────────
const isRankedQuery = isDealValueQuery || isRecencyQuery || isOldestQuery;
const DEFAULT_LIMIT = 15; // max leads shown in a single Telegram message
const showAll = userQuery.includes('all');
const finalLeads = isRankedQuery
  ? leads.slice(0, requestedN || 5)
  : showAll ? leads : leads.slice(0, requestedN || DEFAULT_LIMIT);

// ── 14. Slim fields — includes ALL score-relevant fields ──
const slimLeads = finalLeads.map(l => ({
  name:       l.name       || '',
  email:      l.email      || '',
  phone:      l.phone      || '',
  company:    l.company    || '',
  linkedin:   l.linkedin   || '',
  status:     l.status     || '',
  service:    l.service    || '',
  industry:   l.industry   || '',
  assignedTo: l.assignedTo || '',
  dealValue:  l.dealValue  || 0,
  source:     l.source     || '',
  createdAt:  l.createdAt  || '',
  score:      l.score,
  tier:       l.tier,
  emoji:      l.emoji
}));

// ── 15. Filter summary ────────────────────────────────────
const filtersApplied = [
  assigneeMatch    ? `assignedTo = ${assigneeMatch}`                    : null,
  statusMatch      ? `status = ${statusMatch}`                          : null,
  serviceMatch     ? `service = ${serviceMatch}`                        : null,
  sourceMatch      ? `source = ${sourceMatch}`                          : null,
  companyMatch     ? `company = ${companyMatch}`                        : null,
  filterTier       ? `tier = ${filterTier}`                             : null,
  industryKeyword  ? `industry ~ ${industryKeyword}`                   : null,
  isDealValueQuery ? `sorted by dealValue desc, top ${requestedN}`      : null,
  isOldestQuery    ? `sorted by createdAt asc, top ${requestedN || 5}`  : null,
  isRecencyQuery   ? `sorted by createdAt desc, top ${requestedN || 5}` : null
].filter(Boolean);

return [{ json: {
  success:        data.success !== false,
  source:         data.source         || 'firestore',
  cacheAgeMin:    data.cacheAgeMin    || 0,
  filters:        data.filters        || {},
  total:          data.total          || 0,
  totalAll:       data.totalAll       || data.total || 0,
  totalDealValue: data.totalDealValue || 0,
  aggregations:   data.aggregations   || {},
  topDealsByRep:  data.topDealsByRep  || {},
  leads:          slimLeads,
  _meta: {
    totalLeads:        data.total || 0,
    filteredCount:     slimLeads.length,
    filtersApplied:    filtersApplied.length > 0 ? filtersApplied : ['none'],
    sortedByDealValue: isDealValueQuery || false,
    sortedByRecency:   isRecencyQuery   || false,
    sortedByOldest:    isOldestQuery    || false,
    companyFilter:     companyMatch     || null,
    tierFilter:        filterTier       || null,
    mentionedTiers:    mentionedTiers   || [],
    multiTier:         multiTier        || false,
    tierCount
  }
}}];

// ============================================================
// BUILD SYSTEM PROMPT PAYLOAD  — Tenant-Scoped
// ============================================================
const d = $input.first().json;
const sd = $getWorkflowStaticData('global');

if (d.refreshBlocked) {
  sd['lastCacheSource'] = sd['lastCacheSource'] || 'cache';
  return [{ json: { leadsPayload: null, isRefreshCommand: true, formatted: d.refreshBlockMsg }}];
}

if (d.fatalError) {
  sd['lastCacheSource'] = 'unavailable';
  return [{ json: {
    leadsPayload: JSON.stringify({
      success: false,
      error:   d.error || 'Fatal upstream error \u2014 tenantId could not be resolved.',
      leads:   [],
      aggregations: {}
    })
  }}];
}

let aggregations = d.aggregations || {};
if (aggregations.statusBreakdown && !aggregations.status) {
  aggregations = {
    status:     aggregations.statusBreakdown,
    service:    aggregations.service    || {},
    industry:   aggregations.industry   || {},
    assignedTo: aggregations.assignedTo || {},
    source:     aggregations.source     || {},
    company:    aggregations.company    || {}
  };
}

const assignedToRaw = aggregations.assignedTo || {};
const assignedToCased = {};
for (const [name, count] of Object.entries(assignedToRaw)) {
  const display = name.trim() || 'Unassigned';
  assignedToCased[display] = (assignedToCased[display] || 0) + count;
}
aggregations.assignedTo = assignedToCased;

const sourceLabel = d.source === 'cache'
  ? `cached \u2014 ${d.cacheAgeMin || 0} min ago (auto-refreshes every 4 hours; type refresh to force update)`
  : `live from your CRM (just fetched)`;

sd['lastCacheSource'] = sourceLabel;

const payload = {
  success:        d.success !== false,
  tenantScoped:   true,
  source:         d.source     || 'firestore',
  cacheSource:    sourceLabel,
  dataFooter:     `_(Data: ${sourceLabel})_`,
  filters:        d.filters        || {},
  total:          d.total          || 0,
  totalAll:       d.totalAll       || d.total || 0,
  totalDealValue: d.totalDealValue || 0,
  repSummary:     Object.entries(assignedToCased)
                    .filter(([k]) => k !== 'Unassigned')
                    .map(([name, count]) => `${name}: ${count} leads`)
                    .join(', ') || 'no reps assigned',
  aggregations,
  leads:          d.leads          || [],
  _meta:          d._meta          || {}
};

const userMsg = ($('Telegram Trigger').first().json?.message?.text || '').toLowerCase().trim();

// ── Refresh command detection ──────────────────────────────────────────────
// IMPORTANT: 'reset' is intentionally excluded from this list.
// 'resetevodesk' is a super-admin command routed exclusively through
// Command Router → Lookup User Role → Is Admin? → resetFullCache.
// Including 'reset' here would let any user (incl. agent role) trigger
// a fake "✅ Data refreshed!" response by typing 'resetevodesk'.
const REFRESH_KEYWORDS = ['refresh', 'reload', 'update data', 'clear cache'];
const isRefreshCommand = REFRESH_KEYWORDS.some(kw => userMsg === kw || userMsg.includes(kw));

if (userMsg.startsWith('/addlead') || userMsg.startsWith('/newlead')) {
  return [{ json: {
    leadsPayload: null,
    isBlocked: true,
    formatted: '\u2795 To add a lead, type /addlead and follow the steps.'
  }}];
}

if (isRefreshCommand) {
  return [{ json: {
    leadsPayload: null,
    isRefreshCommand: true,
    formatted: '\u2705 Data refreshed! Your CRM data is now up to date.\n<i>(Data: live from your CRM (just fetched))</i>'
  }}];
}

// \u2500\u2500 Shared helpers \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500
function pad(s, n)  { return String(s).padEnd(n); }
function rpad(s, n) { return String(s).padStart(n); }
function esc(s)     { return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }
function cap(s) {
  const acronyms = new Set(['ai', 'crm', 'erp', 'api', 'hr', 'it', 'b2b', 'b2c', 'saas']);
  return s.split(' ').map(w =>
    acronyms.has(w.toLowerCase()) ? w.toUpperCase() : w.charAt(0).toUpperCase() + w.slice(1)
  ).join(' ');
}

// \u2500\u2500 SUMMARY INTENT \u2014 build directly, skip AI \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500
const isSummaryIntent = ['pipeline', 'summary', 'overview']
  .some(kw => userMsg.includes(kw))
  || userMsg === 'summary'
  || userMsg === 'pipeline';

if (isSummaryIntent) {
  const statusRaw = aggregations.status || {};

  const rows = Object.entries(statusRaw)
    .filter(([k, v]) => k !== '__other__' && v > 0)
    .map(([k, v]) => ({ name: k, count: v }))
    .sort((a, b) => b.count - a.count);

  const total = rows.reduce((s, r) => s + r.count, 0) || payload.total || 0;

  const C1 = 7, C2 = 20, C3 = 11;
  const sep = '-'.repeat(C1 + C2 + C3);
  const hdr = pad('Count', C1) + pad('Stage', C2) + rpad('Percentage', C3);
  const tableRows = rows.map(r => {
    const pct = total > 0 ? Math.round((r.count / total) * 100) : 0;
    return pad(r.count, C1) + pad(cap(r.name), C2) + rpad(pct + '%', C3);
  }).join('\n');
  const totRow = pad(total, C1) + pad('Total', C2) + rpad('100%', C3);
  const table = hdr + '\n' + sep + '\n' + tableRows + '\n' + sep + '\n' + totRow;

  const totalDeal = payload.totalDealValue || 0;
  const won       = statusRaw['won'] || 0;
  const closed    = (statusRaw['won'] || 0) + (statusRaw['lost'] || 0);
  const winRate   = closed > 0 ? Math.round((won / closed) * 100) + '%' : 'N/A';

  const repEntries = Object.entries(assignedToCased)
    .filter(([k]) => k !== 'Unassigned')
    .sort((a, b) => b[1] - a[1]);
  const topRep = repEntries.length > 0
    ? `${repEntries[0][0]} (${repEntries[0][1]})`
    : 'N/A';

  const srcEntries = Object.entries(aggregations.source || {})
    .filter(([k]) => k !== 'unknown')
    .sort((a, b) => b[1] - a[1]);
  const topSrc = srcEntries.length > 0
    ? `${cap(srcEntries[0][0])} (${srcEntries[0][1]})`
    : 'N/A';

  const dealFmt = totalDeal > 0 ? totalDeal.toLocaleString('en-IN') : '0';

  const kpi = [
    pad('Deal Value:', 14)  + dealFmt,
    pad('Win rate:', 14)    + `${winRate} (${won} won / ${closed} closed)`,
    pad('Top rep:', 14)     + topRep,
    pad('Top source:', 14)  + topSrc,
  ].join('\n');

  const formatted =
    '<b>Pipeline Summary</b>\n' +
    '<pre>' + kpi   + '</pre>\n' +
    '<pre>' + table + '</pre>\n' +
    '<i>(Data: ' + esc(sourceLabel) + ')</i>';

  return [{ json: { leadsPayload: null, isRefreshCommand: true, formatted }}];
}

// \u2500\u2500 SERVICE BREAKDOWN \u2014 build directly, skip AI \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500
const isServiceIntent = userMsg.includes('service');

if (isServiceIntent) {
