  const rows = Object.entries(serviceRaw)
    .filter(([k, v]) => k.length > 1 && v > 0)
    .map(([k, v]) => ({ name: k === 'unknown' ? 'Not Set' : k, count: v }))
    .sort((a, b) => b.count - a.count);

  const total = rows.reduce((s, r) => s + r.count, 0) || payload.total || 0;

  const C1 = 7, C2 = 28, C3 = 8;
  const sep = '-'.repeat(C1 + C2 + C3);
  const hdr = pad('Count', C1) + pad('Name', C2) + rpad('Percent', C3);
  const tableRows = rows.map(r => {
    const pct = total > 0 ? Math.round((r.count / total) * 100) : 0;
    return pad(r.count, C1) + pad(cap(r.name), C2) + rpad(pct + '%', C3);
  }).join('\n');
  const totRow = pad(total, C1) + pad('Total', C2) + rpad('100%', C3);
  const table = hdr + '\n' + sep + '\n' + tableRows + '\n' + sep + '\n' + totRow;

  const formatted =
    '<b>\uD83D\uDCCA Service Breakdown</b>\n' +
    '<pre>' + table + '</pre>\n' +
    '<i>(Data: ' + esc(sourceLabel) + ')</i>';

  return [{ json: { leadsPayload: null, isRefreshCommand: true, formatted }}];
}

// \u2500\u2500 INDUSTRY BREAKDOWN \u2014 build directly, skip AI \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500
const isIndustryIntent = userMsg.includes('industry');

if (isIndustryIntent) {
