// \u2500\u2500 COMPANY BREAKDOWN \u2014 build directly, skip AI \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500
const isCompanyIntent =
  userMsg.includes('company') ||
  userMsg.includes('companies') ||
