if (isCompanyIntent) {
  const companyRaw = aggregations.company || {};

  const rows = Object.entries(companyRaw)
    .filter(([k, v]) => k.length > 1 && v > 0)
    .map(([k, v]) => ({ name: k, count: v }))
    .sort((a, b) => b.count - a.count);

  const total = rows.reduce((s, r) => s + r.count, 0) || payload.total || 0;

  const C1 = 7, C2 = 28, C3 = 8;
  const sep = '-'.repeat(C1 + C2 + C3);
  const hdr = pad('Count', C1) + pad('Name', C2) + rpad('Percent', C3);
  const tableRows = rows.map(r => {
    const pct = total > 0 ? Math.round((r.count / total) * 100) : 0;
    return pad(r.count, C1) + pad(r.name, C2) + rpad(pct + '%', C3);
  }).join('\n');
  const totRow = pad(total, C1) + pad('Total', C2) + rpad('100%', C3);
  const table = hdr + '\n' + sep + '\n' + tableRows + '\n' + sep + '\n' + totRow;

  const formatted =
    '<b>\uD83C\uDFE2 Company Breakdown</b>\n' +
    '<pre>' + table + '</pre>\n' +
    '<i>(Data: ' + esc(sourceLabel) + ')</i>';

  return [{ json: { leadsPayload: null, isRefreshCommand: true, formatted }}];
}

// \u2500\u2500 LEADS LIST \u2014 build directly, skip AI \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500
const isLeadsListIntent =
  userMsg.includes('show') ||
  userMsg.includes('list') ||
  userMsg.includes('leads for') ||
  userMsg.includes('leads does') ||
  userMsg.includes('leads by') ||
  userMsg.includes('who has') ||
  userMsg.includes('hot leads') ||
  userMsg.includes('warm leads') ||
  userMsg.includes('cold leads') ||
  userMsg.includes('top deals') ||
  userMsg.includes('top leads') ||
  userMsg.includes('latest') ||
  userMsg.includes('oldest') ||
  userMsg.includes('recent') ||
  userMsg.includes('how many');

if (isLeadsListIntent) {
  const leads = d.leads || [];
  const meta  = d._meta || {};

  const filtersApplied = Array.isArray(meta.filtersApplied)
    ? meta.filtersApplied.filter(f => f !== 'none')
    : [];
  const filterLabel = filtersApplied.length > 0
    ? filtersApplied.join(', ')
    : null;

  // \u2500\u2500 "How many" \u2014 count only, no table \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500
  const isCountOnly = userMsg.includes('how many');
  if (isCountOnly) {
    const count = meta.filteredCount ?? leads.length;
    const formatted =
      `<b>\uD83D\uDD22 Lead Count</b>\n` +
      `<pre>${count} lead${count !== 1 ? 's' : ''}${filterLabel ? '\nFilter: ' + filterLabel : ''}</pre>\n` +
      `<i>(Data: ${esc(sourceLabel)})</i>`;
    return [{ json: { leadsPayload: null, isRefreshCommand: true, formatted }}];
  }

  // \u2500\u2500 Funnel View table \u2500\u2500
  const tierEmoji = { HOT: '\uD83D\uDD34', WARM: '\uD83D\uDFE1', COLD: '\uD83D\uDD35' };

  const shown = leads.length;
  const total = meta.totalLeads || payload.total || 0;
  const _excl = new Set(['won', 'lost']);
  const totalDeal = leads.filter(l => !_excl.has((l.status||'').toLowerCase().trim())).reduce((s, l) => s + (l.dealValue || 0), 0);

  const isDateQuery = meta.sortedByRecency || meta.sortedByOldest;

  const C1 = 6, C2 = isDateQuery ? 22 : 28, C3 = isDateQuery ? 8 : 10, C4 = 10;
  const sepLen = isDateQuery ? C1 + C2 + C3 + C4 : C1 + C2 + C3;
  const sep = '-'.repeat(sepLen);
  const hdr = isDateQuery
    ? '   ' + pad('Name \u2014 Company', C2 - 2) + rpad('Deal', C3) + '  ' + 'Date'
    : '   ' + pad('Name \u2014 Company', C2 - 2) + rpad('Deal', C3);

  const tableRows = leads.map(l => {
    const emoji    = tierEmoji[l.tier] || '\u26AA';
    const nameCol  = (l.name || '\u2014').substring(0, isDateQuery ? 10 : 13);
    const coCol    = (l.company || 'N/A').substring(0, isDateQuery ? 8 : 10);
    const nameComp = `${nameCol} \u2014 ${coCol}`;
    const deal     = l.dealValue > 0 ? l.dealValue.toLocaleString('en-IN') : '\u2014';
    if (isDateQuery) {
      const dt = l.createdAt ? new Date(l.createdAt).toLocaleDateString('en-IN', { day:'2-digit', month:'short', year:'2-digit' }) : '\u2014';
      return emoji + ' ' + pad(nameComp.substring(0, C2 - 2), C2 - 2) + rpad(deal, C3) + '  ' + dt;
    }
    return emoji + ' ' + pad(nameComp.substring(0, C2 - 2), C2 - 2) + rpad(deal, C3);
  }).join('\n');

  const totRow = pad(shown, C1) +
    pad('Total', C2) +
    rpad(totalDeal > 0 ? totalDeal.toLocaleString('en-IN') : '\u2014', C3);

  const table = hdr + '\n' + sep + '\n' + tableRows + '\n' + sep + '\n' + totRow;

  const tierCount = meta.tierCount || {};
  const countLine = shown === total
    ? `${shown} lead${shown !== 1 ? 's' : ''}`
    : `${shown} of ${total} leads`;
  const tierLine = `\uD83D\uDD34 ${tierCount.HOT || 0}  \uD83D\uDFE1 ${tierCount.WARM || 0}  \uD83D\uDD35 ${tierCount.COLD || 0}`;

  const titleLine = filterLabel
    ? `\uD83D\uDCCB <b>Lead View</b> \u2014 ${countLine}  ${tierLine} | Filter: ${filterLabel}`
    : `\uD83D\uDCCB <b>Lead View</b> \u2014 ${countLine}  ${tierLine}`;

  const formatted =
    titleLine + '\n' +
    '<pre>' + table + '</pre>\n' +
    '<i>(Data: ' + esc(sourceLabel) + ')</i>';

  return [{ json: { leadsPayload: null, isRefreshCommand: true, formatted }}];
}

