const greetingWords = ['hi', 'hello', 'hey', 'hii', 'helo', 'namaste', 'good morning', 'good afternoon', 'good evening', 'start', '/start'];
const isGreeting = greetingWords.some(g => userMsg === g || userMsg.startsWith(g + ' ') || userMsg.startsWith(g + '!'));

if (isGreeting) {
