  }}];
}

const isAllowed = allowedIntents.some(intent => userMsg.includes(intent));

if (!isAllowed) {
  return [{ json: {
    leadsPayload: null,
    isBlocked: true,
    formatted: `\u26A0\uFE0F I can only help with lead and pipeline questions.\n\nTry asking:\n\u2022 "How many leads does Chandrashekhar have?"\n\u2022 "Show me the pipeline summary"\n\u2022 "What is our win rate?"\n\n\uD83D\uDCA1 Type <b>hi</b> to see all available commands.\n\n<i>(Data: ${esc(sourceLabel)})</i>`
  }}];
