// ============================================================

const d = $input.first().json;

if (d.isRefreshCommand) { return [{ json: { formatted: d.formatted } }]; }
if (d.isBlocked)        { return [{ json: { formatted: d.formatted } }]; }

let text = (d.output || '').replace(/\\n/g, '\n');

// Strip AI-appended footer
text = text.replace(/\n?_\(Data:.*?\)_\s*$/s, '').trimEnd();

// Fix __other__ and escaped underscores
text = text.replace(/__other__/gi, 'Other');
text = text.replace(/\\_/g, '_');

// Convert markdown bold to HTML bold
text = text.replace(/\*\*(.*?)\*\*/g, '<b>$1</b>');

// Convert bullet points
