  .replace("Here's a summary of your current leads:", '<b>\ud83d\udcca Lead Summary</b>\n')
  .replace('Pipeline Stages:',    '<b>\ud83d\udccc Pipeline Stages</b>')
  .replace('Win Rate:',           '<b>\ud83c\udfc6 Win Rate:</b>')
