// ============================================================
// READ USER→TENANT MAP CACHE  v2.2
// Checks static data for existing telegramUserId → tenantId mapping.
// TTL: 24 hours per user
//
// FIXES:
//   v2.0 — Added _sd_key_count diagnostic to detect empty static data
//   v2.1 — Guard against mapCachedAt=0 treated as "never written"
//   v2.2 — Sync MAP_TS_KEY prefix to 'umap_ts_' (matching Save node v2.0)
//           so timestamp lookups succeed after resetFullCache.
// ============================================================

const sd  = $getWorkflowStaticData('global');
const msg = $('Telegram Trigger').first().json?.message;

const telegramUserId = String(msg?.from?.id || '');
const username       = msg?.from?.username   || '';
const firstName      = msg?.from?.first_name || '';
const chatId         = String(msg?.chat?.id  || msg?.from?.id || '');

// ── DIAGNOSTIC: log key count to detect static data persistence issues ────
// If this is always 0 across executions, you are likely running in queue
// mode (EXECUTIONS_MODE=queue) with multiple workers. Static data is
// per-process and not shared across workers — switch to a Redis-based cache
// or set EXECUTIONS_MODE=regular to fix.
const _sdKeyCount = Object.keys(sd).length;

if (!telegramUserId) {
  return [{
    json: {
      userMapFound:   false,
      telegramUserId: null,
      tenantId:       null,
      chatId,
      error:          'No Telegram user ID in payload',
      fatalError:     true,
      _sdKeyCount
    }
  }];
}

const MAP_KEY    = 'user_tenant_map';
// FIX v2.2: Must match Save node's key — was 'user_tenant_map_ts_', now 'umap_ts_'
const MAP_TS_KEY = `umap_ts_${telegramUserId}`;
const MAP_TTL    = 24 * 60 * 60 * 1000;

let userMap = {};
try { userMap = sd[MAP_KEY] ? JSON.parse(sd[MAP_KEY]) : {}; } catch { userMap = {}; }

const mapCachedAt = sd[MAP_TS_KEY] ? Number(sd[MAP_TS_KEY]) : 0;
const mapAgeMs    = Date.now() - mapCachedAt;

// Expired only if timestamp exists AND is old. Missing timestamp = Firebase re-check.
const mapExpired = mapCachedAt > 0 ? mapAgeMs > MAP_TTL : true;

// Only accept new {tenantId, role} object format.
const rawEntry    = userMap[telegramUserId] || null;
const isNewFormat = rawEntry && typeof rawEntry === 'object';
const tenantId    = isNewFormat ? rawEntry.tenantId : null;
const cachedRole  = isNewFormat ? rawEntry.role      : null;

if (tenantId && cachedRole && !mapExpired) {
  return [{
    json: {
      userMapFound:   true,
      telegramUserId,
      username,
      firstName,
      chatId,
      tenantId,
      userRole:       cachedRole,
      mapAgeHours:    Math.floor(mapAgeMs / 3600000),
      _sdKeyCount
    }
  }];
}

return [{
  json: {
    userMapFound:   false,
    telegramUserId,
    username,
    firstName,
    chatId,
    tenantId:       null,
    _sdKeyCount,
    _missReason:    !tenantId ? 'no_entry_or_bad_format' : (mapExpired ? 'ts_expired' : 'unknown')
  }
}];

// ============================================================
// SAVE USER→TENANT MAP CACHE  v2.1
// Firebase confirmed user exists — write mapping to static data.
//
// FIXES:
//   v2.0 — Changed MAP_TS_KEY prefix from 'user_tenant_map_ts_' to 'umap_ts_'
//           so resetFullCache (which deletes keys starting with 'user_tenant_map')
//           does NOT accidentally nuke per-user timestamp keys.
//           The shared map blob ('user_tenant_map') IS correctly deleted on reset.
//           Per-user timestamps survive so fresh saves re-use and re-stamp them.
// ============================================================

const sd  = $getWorkflowStaticData('global');
const doc = $input.first().json;

// Fields from Firebase user doc
const tenantId   = doc.tenant_id   || doc.fields?.tenant_id?.stringValue   || null;
const isActive   = doc.active !== false && doc.isActive !== false;
const userName   = doc.name        || doc.username                          || '';
const userEmail  = doc.email       || doc.fields?.email?.stringValue        || '';
const userRole   = (
  doc.role                          ||
  doc.fields?.role?.stringValue     ||
  'user'
).toString().toLowerCase().trim();

// Telegram context from upstream
const telegramCtx    = $('Read User→Tenant Map').first().json;
const telegramUserId = telegramCtx.telegramUserId;
const chatId         = telegramCtx.chatId;
const firstName      = telegramCtx.firstName || '';
const username       = telegramCtx.username  || '';

if (!tenantId || !telegramUserId) {
  return [{
    json: {
      userMapFound: false,
      tenantId:     null,
      error:        'Cannot cache — tenantId or telegramUserId missing',
      fatalError:   true
    }
  }];
}

if (isActive) {
  const MAP_KEY    = 'user_tenant_map';
  // FIX: prefix changed from 'user_tenant_map_ts_' → 'umap_ts_'
  // resetFullCache deletes keys starting with 'user_tenant_map' which
  // correctly wipes the shared map blob but now leaves per-user timestamps intact.
  const MAP_TS_KEY = `umap_ts_${telegramUserId}`;

  let userMap = {};
  try { userMap = sd[MAP_KEY] ? JSON.parse(sd[MAP_KEY]) : {}; } catch { userMap = {}; }

  const isNewUser = !userMap[telegramUserId];
  userMap[telegramUserId] = { tenantId, role: userRole };

  sd[MAP_KEY]    = JSON.stringify(userMap);
  sd[MAP_TS_KEY] = String(Date.now());

  return [{
    json: {
      userMapFound:     true,
      registered:       true,
      isNewUser,
      isActive:         true,
      telegramUserId,
      chatId,
      firstName,
      username,
      tenantId,
      userEmail,
      userName,
      userRole,
      totalMappedUsers: Object.keys(userMap).length
    }
  }];
}

// Inactive — don't cache, pass isActive:false for Active? node to catch
return [{
  json: {
    userMapFound:  true,
    registered:    true,
    isActive:      false,
    telegramUserId,
    chatId,
    firstName,
    username,
    tenantId,
    userEmail,
    userName,
    userRole
  }
}];

// ============================================================
// USER NOT REGISTERED
// No matching user doc in Firebase. Return a message payload
// that the Telegram Send node can deliver directly.
// ============================================================

const ctx            = $('Read User→Tenant Map').first().json;
const telegramUserId = ctx.telegramUserId || 'unknown';
const firstName      = ctx.firstName      || 'there';
const chatId         = ctx.chatId         || telegramUserId;

return [{
  json: {
    chatId,
    formatted: `Hi ${firstName}, your Telegram account is not registered in the system.\n\nPlease contact your administrator to get access.\n\n<b>User ID:</b> <code>${telegramUserId}</code>`,
    notRegistered: true,
    fatalError:    false
  }
}];

// ============================================================
