// ============================================================

const ctx          = $('Save User→Tenant Map').first().json;
const firstName    = ctx.firstName || 'there';
const chatId       = ctx.chatId    || ctx.telegramUserId;

return [{
  json: {
    chatId,
    formatted:    `Hi ${firstName}, your account has been deactivated.\n\nPlease contact your administrator to restore access.`,
    userInactive: true
  }
}];

