  if (reason === 'input_passthrough_429' || reason === 'telegram_passthrough_429' || reason === 'pipeline_passthrough_429') {
    return '429 · Quota exceeded (RESOURCE_EXHAUSTED)';
  }
  if (httpCode === 429 || errMsg.includes('quota') || errMsg.includes('too many')) return '429 · Quota exceeded (RESOURCE_EXHAUSTED)';
  if (httpCode === 401 || errMsg.includes('unauthenticated')) return '401 · Unauthenticated — invalid credentials';
