  if (httpCode === 500) return '500 · Internal server error';
  if (httpCode === 503 || errMsg.includes('unavailable')) return '503 · Service unavailable';
  if (httpCode === 408 || errMsg.includes('deadline') || errMsg.includes('timeout')) return '408 · Deadline exceeded';
  if (httpCode) return `${httpCode} · Firebase error`;
  return 'Firebase error (code unknown)';
}

