  userText = '🔐 <b>Authentication issue detected.</b>\n\nThe bot cannot reach the database right now due to a credentials problem. Please contact your administrator — this needs to be fixed on the system side.';
} else if (httpCode === 403 || errMsg.includes('permission') || errMsg.includes('forbidden')) {
