  userText = '⚠️ <b>Something went wrong loading your data.</b>\n\nWe got an empty response from the database — this may be a brief quota hiccup. Please retry in a few seconds.';
} else {
  icon = '⚠️'; techTitle = 'Unexpected Error — User Lookup';
  userText = '⚠️ <b>An unexpected error occurred.</b>\n\nPlease contact your administrator and share the error details below.';
}

const message = buildMessages(userText, icon, techTitle, [
  ['Where',  'Firebase → users collection'],
