             (httpCode === 401 || httpCode === 403) ? 'Admin must fix Firebase credentials / IAM' :
             'Try again or contact admin'],
], `firebase/users/lookup · code ${httpCode} · user ${telegramUserId}`);

return [{ json: { chatId, message } }];

