const httpCode = item?.error?.httpCode || item?.error?.statusCode || item?.statusCode || item?.code || 0;

// Check 1: explicit error object
const hasErrorObj = !!(item?.error);

// Check 2: error keywords in any message field
const hasErrKeyword = ['quota exceeded','too many','unauthenticated','permission denied',
  'unavailable','deadline exceeded','forbidden','invalid credentials'].some(k => errMsg.includes(k));

// Check 3: HTTP error code
const hasErrCode = [429,401,403,500,503,408].includes(Number(httpCode));

// Check 4: result is completely empty (Firestore 429 often returns empty item)
// For user role lookup, a valid result must have at least one recognizable field
const validFields = ['role','tenant_id','telegram_user_id','email','name','active'];
const hasValidData = validFields.some(f => item[f] !== undefined);
const isEmpty = !hasValidData && Object.keys(item).filter(k => !k.startsWith('_')).length === 0;

// FIX: With continueRegularOutput, Firebase 429 passes the INPUT item through unchanged.
// Input items always contain 'telegramUserId'/'route' — Firestore responses never do.
const isInputPassthrough = !!(item?.telegramUserId || item?.chatId || item?.route);

const isError = hasErrorObj || hasErrKeyword || hasErrCode || isEmpty || isInputPassthrough;

return [{ json: { 
  ...item, 
  _isFirebaseError: isError, 
  _httpCode: httpCode, 
  _errMsg: errMsg,
  _isEmpty: isEmpty,
  _debugReason: isError ? (hasErrorObj?'error_obj':hasErrKeyword?'err_keyword':hasErrCode?'err_code':isInputPassthrough?'input_passthrough_429':'empty_result') : 'ok'
}}];

