// ============================================================
// DETECT SUMMARY ERROR — [FIXED v2]
//
// ROOT CAUSE OF THE 101→1 BUG:
//   Original code returned only items[0], discarding items[1..N].
//   This collapsed all 101 Firestore docs into 1 item before the IF node.
//
// FIX:
//   - Error detected? → return single error item (IF → true/error branch).
//   - No error?       → return ALL items tagged _isFirebaseError:false
//                       so IF node passes them all to Aggregate + Save to Cache.
// ============================================================

const items = $input.all();
const first = items[0]?.json || {};

const errMsg    = (first?.error?.message || first?.message || first?.description || '').toLowerCase();
const httpCode  = first?.error?.httpCode || first?.error?.statusCode || first?.statusCode || first?.code || 0;

const hasErrorObj   = !!(first?.error);
const hasErrKeyword = ['quota exceeded','too many','unauthenticated','permission denied',
  'unavailable','deadline exceeded','forbidden','invalid credentials'].some(k => errMsg.includes(k));
const hasErrCode    = [429,401,403,500,503,408].includes(Number(httpCode));

const isTelegramPassthrough = !!(first?.ok === true && first?.result?.message_id);
const isPipelinePassthrough = !!(first?.telegramUserId || first?.chatId || first?.route);

const isError = hasErrorObj || hasErrKeyword || hasErrCode || isTelegramPassthrough || isPipelinePassthrough;

const debugReason = isError
  ? (hasErrorObj           ? 'error_obj'
   : hasErrKeyword         ? 'err_keyword'
   : hasErrCode            ? 'err_code'
   : isTelegramPassthrough ? 'telegram_passthrough_429'
   : isPipelinePassthrough ? 'pipeline_passthrough_429'
   : 'unknown')
  : 'ok';

if (isError) {
  return [{ json: {
    ...first,
    _isFirebaseError:       true,
    _isTelegramPassthrough: isTelegramPassthrough,
    _httpCode:              httpCode,
    _errMsg:                errMsg,
    _debugReason:           debugReason
  }}];
}

// No error — pass ALL items through so Aggregate + Save to Cache sees every lead
return items.map(it => ({
  json: {
    ...it.json,
    _isFirebaseError:       false,
    _isTelegramPassthrough: false,
    _httpCode:              0,
    _errMsg:                '',
    _debugReason:           'ok'
  }
}));

