// Detect Firebase error on Update leadId (upsert)  v3
//
// ROOT CAUSE OF FALSE POSITIVES:
//   The Firestore upsert node does NOT return _id or _name on success —
//   it echoes back the input columns. Set Lead ID also spreads the full
//   upstream item (...input) so chatId/telegramUserId are always present.
//   This made every success look like a passthrough, and every passthrough
//   check keyed on those fields was always true.
//
// CORRECT APPROACH FOR UPSERT:
//   Unlike create, upsert has no useful success metadata to check.
//   If there are NO error signals at all (no error object, no error
//   keywords, no error HTTP code) it succeeded. No passthrough heuristic.

const items = $input.all();
const item = items[0]?.json || {};
const errMsg = (item?.error?.message || item?.message || item?.description || '').toLowerCase();
const httpCode = item?.error?.httpCode || item?.error?.statusCode || item?.statusCode || item?.code || 0;

const hasErrorObj   = !!(item?.error);
const hasErrKeyword = ['quota exceeded','too many','unauthenticated','permission denied',
  'unavailable','deadline exceeded','forbidden','invalid credentials'].some(k => errMsg.includes(k));
const hasErrCode    = [429,401,403,500,503,408].includes(Number(httpCode));

// For upsert: no error signals at all = success. No passthrough heuristic needed.
const isError = hasErrorObj || hasErrKeyword || hasErrCode;

return [{ json: {
  ...item,
  _isFirebaseError: isError,
  _httpCode: httpCode,
  _errMsg: errMsg,
  _debugReason: isError
    ? (hasErrorObj   ? 'error_obj'
     : hasErrKeyword ? 'err_keyword'
     : hasErrCode    ? 'err_code'
     : 'unknown')
    : 'ok'
}}];

